const dashboard = $('Get Dashboard Stats (Sellf API)').first().json;
const topProducts = $('Get Top Products (Sellf API)').first().json;

const stats = dashboard.data || dashboard;
const products = (topProducts.data || topProducts.products || []).slice(0, 5);

const topList = products.length > 0
  ? products.map((p, i) => `  ${i+1}. ${p.name || p.product_name} — ${p.revenue || p.total_revenue || 0}`).join('\n')
  : '  Brak sprzedaży';

const msg = `📊 *Sellf Daily Report*\n` +
  `📅 ${new Date().toLocaleDateString('pl-PL')}\n\n` +
  `💰 Przychód dziś: *${stats.revenue_today || stats.todayRevenue || 0}*\n` +
  `🛒 Zamówienia dziś: *${stats.orders_today || stats.todayOrders || 0}*\n` +
  `👥 Aktywni użytkownicy: *${stats.active_users || stats.activeUsers || 0}*\n` +
  `📦 Aktywne produkty: *${stats.active_products || stats.activeProducts || 0}*\n\n` +
  `🏆 *Top produkty (dziś):*\n${topList}`;

return [{ json: { message: msg } }];
